	for _, item := range items {
		// Create a new VM for each item to prevent state leakage
		vm := otto.New()
		disableDangerousGlobals(vm)

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Set a timeout to prevent infinite loops
		done := make(chan bool, 1)
		var scriptValue otto.Value
		var scriptErr error

		go func() {
			defer func() {
				// Recover from potential panics (e.g., stack overflow)
				if r := recover(); r != nil {
					done <- false
					return
				}
				done <- true
			}()

			// Run the condition script
			scriptValue, scriptErr = vm.Run(conditionScript)
