// disableDangerousGlobals removes access to potentially dangerous global objects
func disableDangerousGlobals(vm *otto.Otto) {
	// Remove dangerous built-in objects
	vm.Set("eval", nil)
	vm.Set("Function", nil)
	vm.Set("setTimeout", nil)
	vm.Set("setInterval", nil)
	vm.Set("clearTimeout", nil)
	vm.Set("clearInterval", nil)

	// Remove global objects that could be used for system access
	vm.Set("process", nil)
	vm.Set("require", nil)
	vm.Set("module", nil)
	vm.Set("global", nil)
	vm.Set("window", nil)
	vm.Set("document", nil)
	vm.Set("XMLHttpRequest", nil)
	vm.Set("fetch", nil)

