	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of data items based on a JavaScript condition script.
// The script is executed for each item, with the current item available as the global variable 'item'.
// Items for which the script evaluates to true are included in the returned slice.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	vm := otto.New()
	var filteredItems []map[string]interface{}

	for _, item := range items {
		// Set the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Execute the condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err
		}

		// Convert the result to a boolean
		boolValue, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolValue {
			filteredItems = append(filteredItems, item)
		}
	}

	return filteredItems, nil
}

